// See https://wxt.dev/api/config.html
export default defineConfig({
        // See https://developer.chrome.com/docs/extensions/reference/manifest
        manifest: ({ browser }) => ({
                name: 'Better Surf',
                description: '더 나은 웹 서핑을 위한 소소하지만 강력한 도구들',
                host_permissions: [
                        'https://*.epost.go.kr/*',
                        'https://buttr.dev/*',
                        'https://cdn.hancom.com/*',
