import { mkdtempSync, rmSync, writeFileSync, mkdirSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { resolveConfig } from '/workspace/wxt/packages/wxt/src/core/resolve-config.ts';

const keys = ['CHROME_EXTENSION_ID', 'FIREFOX_EXTENSION_ID', 'WXT_WATCH_DEBOUNCE'];
const previous = Object.fromEntries(keys.map((key) => [key, process.env[key]]));
for (const key of keys) delete process.env[key];

const root = mkdtempSync(join(tmpdir(), 'wxt-dotenv-repro-'));

async function main() {
try {
  writeFileSync(
    join(root, '.env'),
    'CHROME_EXTENSION_ID=chrome-from-dotenv\nFIREFOX_EXTENSION_ID=firefox-from-dotenv\nWXT_WATCH_DEBOUNCE=123\n',
  );
  mkdirSync(join(root, 'entrypoints'));
  writeFileSync(
    join(root, 'wxt.config.ts'),
    `export default {
      manifest: () => {
        const missing = ['CHROME_EXTENSION_ID', 'FIREFOX_EXTENSION_ID'].filter((key) => !process.env[key]);
        if (missing.length) throw new Error('Missing required config: ' + missing.join(', '));
        return {
          name: 'dotenv repro',
          version: '1.0.0',
          oauth2: { client_id: process.env.CHROME_EXTENSION_ID },
          browser_specific_settings: { gecko: { id: process.env.FIREFOX_EXTENSION_ID } },
        };
      },
    }`,
  );

  process.chdir(root);
  const config = await resolveConfig({ root }, 'build');
  if (config.manifest.oauth2?.client_id !== 'chrome-from-dotenv') {
    throw new Error('Manifest did not receive CHROME_EXTENSION_ID from .env');
  }
  if (config.dev.server?.watchDebounce != null) {
    throw new Error('Build config unexpectedly had dev server config');
  }
  console.log('repro passed: .env values reached manifest config');
} finally {
  for (const [key, value] of Object.entries(previous)) {
    if (value == null) delete process.env[key];
    else process.env[key] = value;
  }
  rmSync(root, { recursive: true, force: true });
}
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});

